class Solution:
    def maximumSum(self, nums: List[int]) -> int:
        groups = defaultdict(list)
        for num in nums:
            sf = self.square_free(num)
            groups[sf].append(num)

        max_sum = 0
        for key in groups:
            total = sum(groups[key])
            if total > max_sum:
                max_sum = total
        return max_sum

    def square_free(self, x: int) -> int:
        sf = 1
        i = 2
        while i * i <= x:
            count = 0
            while x % i == 0:
                x //= i
                count += 1
            if count % 2 == 1:
                sf *= i
            i += 1
        if x > 1:
            sf *= x
        return sf

