class Solution:
    def maxSum(self, nums: List[int], k: int) -> int:
        MOD = 10**9 + 7
        bits = [0] * 31  # since 2^30 is about 1e9

        # Count the number of 1s for each bit position
        for num in nums:
            for b in range(31):
                if num & (1 << b):
                    bits[b] += 1

        # Compute s[b] for each bit
        s = [0] * 31
        for b in range(31):
            s[b] = min(bits[b], k)

        total = 0
        for i in range(k):
            current = 0
            for b in range(31):
                if s[b] > i:
                    current += (1 << b)
            total += current * current

        return total % MOD

