    def minGroupsForValidAssignment(self, nums: List[int]) -> int:
        freq = list(Counter(nums).values())
        if not freq:
            return 0
        max_freq = max(freq)

        low = 1
        high = max_freq
        best_m = 1

        while low <= high:
            mid = (low + high) // 2
            valid = True
            if mid == 1:
                valid = True
            else:
                for f in freq:
                    ceil_f_m = (f + mid - 1) // mid
                    floor_f_m_1 = f // (mid - 1)
                    if ceil_f_m > floor_f_m_1:
                        valid = False
                        break
            if valid:
                best_m = mid
                low = mid + 1
            else:
                high = mid - 1

        total = 0
        for f in freq:
            total += (f + best_m - 1) // best_m

        return total

