class Solution:
    def countCompleteSubstrings(self, word: str, k: int) -> int:
        segments = []
        if not word:
            return 0
        current_segment = [word[0]]
        for i in range(1, len(word)):
            prev_char = word[i-1]
            curr_char = word[i]
            if abs(ord(prev_char) - ord(curr_char)) > 2:
                segments.append(''.join(current_segment))
                current_segment = [curr_char]
            else:
                current_segment.append(curr_char)
        segments.append(''.join(current_segment))

        total = 0
        for seg in segments:
            n = len(seg)
            for m in range(1, 27):
                L = m * k
                if L > n:
                    continue
                # Initialize frequency array
                freq = [0] * 26
                # Fill first window
                for i in range(L):
                    c = seg[i]
                    freq[ord(c) - ord('a')] += 1
                # Check first window
                valid_count = 0
                unique = 0
                for i in range(26):
                    if freq[i] > 0:
                        unique += 1
                        if freq[i] == k:
                            valid_count += 1
                if unique == m and valid_count == m:
                    total += 1
                # Slide the window
                for i in range(1, n - L + 1):
                    # Remove the leftmost character of previous window
                    left_char = seg[i-1]
                    freq[ord(left_char) - ord('a')] -= 1
                    # Add the new rightmost character
                    right_char = seg[i + L - 1]
                    freq[ord(right_char) - ord('a')] += 1
                    # Check validity
                    valid_count = 0
                    unique = 0
                    for j in range(26):
                        if freq[j] > 0:
                            unique += 1
                            if freq[j] == k:
                                valid_count += 1
                    if unique == m and valid_count == m:
                        total += 1
        return total

